{
  "type": "object",
  "title": "Luma Product Catalog Class",
  "description": "Luma Product Catalog Class",
  "allOf": [
    {
      "$ref": "https://ns.adobe.com/xdm/data/record"
    }
  ]
}

{
    "meta:resourceType": "mixins",
    "title": "Luma Product Catalog Field Group",
    "type": "object",
    "description": "",
    "properties": {
        "{{TENANT_ID}}": {
            "type": "object",
            "properties": {
                "product": {
                    "type": "object",
                    "properties": {
                        "sku": {
                            "title": "Product SKU",
                            "description": "Unique identifier of the product",
                            "type": "string",
                            "isRequired": true,
                            "meta:xdmType": "string"
                        },
                        "name": {
                            "title": "Product Name",
                            "description": "Name of the product",
                            "type": "string",
                            "isRequired": false,
                            "meta:xdmType": "string"
                        },
                        "category": {
                            "title": "Product Category",
                            "description": "Category of the product",
                            "type": "string",
                            "isRequired": false,
                            "meta:xdmType": "string"
                        },
                        "color": {
                            "title": "Product Color",
                            "description": "Color of the product",
                            "type": "string",
                            "isRequired": false,
                            "meta:xdmType": "string"
                        },
                        "size": {
                            "title": "Product Size",
                            "description": "Size of the product",
                            "type": "string",
                            "isRequired": false,
                            "meta:xdmType": "string"
                        },
                        "price": {
                            "title": "Product Price",
                            "description": "Price of the product",
                            "type": "number",
                            "isRequired": false,
                            "meta:xdmType": "number"
                        },
                        "description": {
                            "title": "Product Description",
                            "description": "Description of the product",
                            "type": "string",
                            "isRequired": false,
                            "meta:xdmType": "string"
                        },
                        "imageUrl": {
                            "title": "Product Image URL",
                            "description": "URL of the product thumbnail image used on the Luma website",
                            "type": "string",
                            "isRequired": false,
                            "meta:xdmType": "string"
                        },
                        "url": {
                            "title": "Product URL",
                            "description": "URL of the product detail page on the Luma website",
                            "type": "string",
                            "isRequired": false,
                            "meta:xdmType": "string"
                        },
                        "stockQuantity": {
                            "title": "Product Stock Quantity",
                            "description": "Number of items left in stock",
                            "type": "integer",
                            "isRequired": false,
                            "meta:xdmType": "integer"
                        }
                    },
                "meta:xdmType": "object",
                "required": [
                    "sku"
                ]
                }
            }
        }
    },
    "meta:extensible": true,
    "meta:abstract": true,
    "meta:intendedToExtend": [
        "{{luma_product_catalog_class_id}}"
    ],
    "meta:xdmType": "object"
}

{
  "name": "Luma Product SKU",
  "code": "lumaProductSKU",
  "idType": "Non_people",
  "description": "The id associated with Luma's product sku."
}

{
    "meta:resourceType": "schemas",
    "title": "Luma Product Catalog Schema",
    "type": "object",
    "description": "Luma Product Catalog Schema",
    "allOf": [
        {
            "$ref": "{{luma_product_catalog_class_id}}",
            "type": "object",
            "meta:xdmType": "object"
        },
        {
            "$ref": "{{luma_product_catalog_fieldgroup_id}}",
            "type": "object",
            "meta:xdmType": "object"
        }
    ],
    "meta:extensible": false,
    "meta:abstract": false,
    "meta:extends": [
        "https://ns.adobe.com/xdm/data/record",
        "{{luma_product_catalog_fieldgroup_id}}",
        "{{luma_product_catalog_class_id}}"
    ],
    "meta:xdmType": "object",
    "meta:immutableTags": [
        "union"
    ]
}

{
    "name": "Luma Product Catalog Dataset",
    "schemaRef": {
        "id": "{{luma_product_catalog_schema_id}}",
        "contentType": "application/vnd.adobe.xed-full-notext+json; version=1"
    },
    "fileDescription": {
        "persisted": true,
        "containerFormat": "parquet",
        "format": "parquet"
    },
    "tags": {
        "unifiedProfile": ["enabled:true"],
        "unifiedIdentity": ["enabled:true"]
    },
    "enableErrorDiagnostics": true
}
